import React, { useEffect, useState } from "react";
import { createClient } from "@supabase/supabase-js";
import "./App.css"; // CSS dosyan burada tanımlı

const supabaseUrl = "https://cnakyamdydqxistdavfg.supabase.co";
const supabaseKey =
    "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImNuYWt5YW1keWRxeGlzdGRhdmZnIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NTM5NDIzNTEsImV4cCI6MjA2OTUxODM1MX0.mAVSru38H63peSy0iH6nDdJ0WBxBwQcoVJwYMy9UKBo";

const supabase = createClient(supabaseUrl, supabaseKey);

const columnOrder = [
    "PROJE ADI",
    "TALEP",
    "TEDARİK",
    "VERİLEMEYEN",
    "TED. %",
    "SPOT",
    "FİLO",
    "TESİSTE",
    "GELECEK",
    "YÜKLENDİ",
    "HEDEF ÜSTÜ SEFER",
    "HEDEF ALTI SEFER",
    "HEDEF SEFER",
    "HEDEFSİZ SEFER",
];

function App() {
    const [data, setData] = useState([]);
    const [odakData, setOdakData] = useState([]);
    const [tedarikStats, setTedarikStats] = useState({
        toplam: 0,
        tedarikEdilen: 0,
        tedarikEdilmeyen: 0,
    });

    // Supabase verisi çek
    useEffect(() => {
        async function fetchSupabaseData() {
            const { data, error } = await supabase
                .from("toplu_sonuclar")
                .select("json_data")
                .order("created_at", { ascending: false })
                .limit(1)
                .single();

            if (error) {
                console.error("Supabase veri çekme hatası:", error);
                return;
            }

            if (data && data.json_data) {
                setData(data.json_data);
            }
        }

        fetchSupabaseData();
    }, []);

    // Odak API verisi çek
    useEffect(() => {
        async function fetchOdakData() {
            const today = new Date().toISOString().split("T")[0];
            const payload = {
                startDate: `${today}T00:00:00`,
                endDate: `${today}T23:59:59`,
                userId: 1,
            };

            try {
                const response = await fetch("/api/tmsorders/getall", {
                    method: "POST",
                    headers: {
                        "Content-Type": "application/json",
                        Authorization:
                            "Bearer 49223653afa4b7e22c3659762c835dcdef9725a401e928fd46f697be8ea2597273bf4479cf9d0f7e5b8b03907c2a0b4d58625692c3e30629ac01fc477774de75",
                    },
                    body: JSON.stringify(payload),
                });

                if (!response.ok) {
                    throw new Error("API yanıtı başarılı değil.");
                }

                const result = await response.json();
                const items = result.data || []; // .data varsa al, yoksa boş dizi

                const simplified = items.map((item) => ({
                    ProjectName: item.projectName,
                    TMSVehicleRequestDocumentNo: item.tmsVehicleRequestDocumentNo,
                    TMSDespatchDocumentNo: item.tmsDespatchDocumentNo,
                }));


                setOdakData(simplified);

                const uniqueTalep = [
                    ...new Set(simplified.map((x) => x.TMSVehicleRequestDocumentNo)),
                ].length;
                const tedarikEdilen = simplified.filter(
                    (x) => x.TMSDespatchDocumentNo
                ).length;
                const tedarikEdilmeyen = simplified.filter(
                    (x) => !x.TMSDespatchDocumentNo
                ).length;

                setTedarikStats({
                    toplam: uniqueTalep,
                    tedarikEdilen,
                    tedarikEdilmeyen,
                });
            } catch (err) {
                console.error("Odak API hatası:", err);
            }
        }

        fetchOdakData();
    }, []);


    return (
        <div className="app-container">
            {/* Supabase Tablosu */}
            {data.length > 0 ? (
                <div className="table-wrapper">
                    <h2>Supabase: Toplu Sonuçlar</h2>
                    <table className="styled-table">
                        <thead>
                            <tr>
                                {columnOrder.map((col) => (
                                    <th key={col}>{col}</th>
                                ))}
                            </tr>
                        </thead>
                        <tbody>
                            {data.slice(1).map((row, idx) => (
                                <tr key={idx}>
                                    {columnOrder.map((col, i) => {
                                        const value = row[col];
                                        let displayValue = value;
                                        let style = {};

                                        if (col === "TED. %") {
                                            const parsed = parseFloat(value);
                                            if (!isNaN(parsed)) {
                                                const percentage = Math.round(parsed * 100);
                                                displayValue = `%${percentage}`;

                                                if (percentage < 70) {
                                                    style = { color: "#e74c3c", fontWeight: "bold" };
                                                } else if (percentage < 90) {
                                                    style = { color: "#f39c12", fontWeight: "bold" };
                                                } else {
                                                    style = { color: "#27ae60", fontWeight: "bold" };
                                                }
                                            }
                                        } else if (
                                            col === "HEDEF ÜSTÜ SEFER" ||
                                            col === "HEDEF ALTI SEFER" ||
                                            col === "HEDEF SEFER"
                                        ) {
                                            const parsed = parseFloat(value);
                                            if (!isNaN(parsed)) {
                                                displayValue = `${parsed.toLocaleString("tr-TR")} ₺`;
                                                if (col === "HEDEF ÜSTÜ SEFER") {
                                                    style = {
                                                        color: parsed > 0 ? "#27ae60" : "#e74c3c",
                                                        fontWeight: "bold",
                                                    };
                                                }
                                            }
                                        }

                                        return (
                                            <td key={i} style={style}>
                                                {displayValue}
                                            </td>
                                        );
                                    })}
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            ) : (
                <p className="loading">Yükleniyor...</p>
            )}

            {/* Odak API Tablosu */}
            {odakData.length > 0 && (
                <div className="odak-table">
                    <h2>Odak API: Günlük Tedarik Durumu</h2>
                    <p>
                        <strong>Toplam Talep:</strong> {tedarikStats.toplam}
                    </p>
                    <p>
                        <strong>Tedarik Edilen:</strong> {tedarikStats.tedarikEdilen}
                    </p>
                    <p>
                        <strong>Tedarik Edilmeyen:</strong> {tedarikStats.tedarikEdilmeyen}
                    </p>

                    <table className="styled-table">
                        <thead>
                            <tr>
                                <th>Project Name</th>
                                <th>Vehicle Request No</th>
                                <th>Despatch No</th>
                            </tr>
                        </thead>
                        <tbody>
                            {odakData.map((item, idx) => (
                                <tr key={idx}>
                                    <td>{item.ProjectName}</td>
                                    <td>{item.TMSVehicleRequestDocumentNo}</td>
                                    <td
                                        style={{
                                            color: item.TMSDespatchDocumentNo
                                                ? "#27ae60"
                                                : "#e74c3c",
                                        }}
                                    >
                                        {item.TMSDespatchDocumentNo || "TEDARİK EDİLMEDİ"}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}
        </div>
    );
}

export default App;
